{{(() => {
                    const type = ReportTypeSelect.selectedOptionValue;
                    switch(type) {
                      case 'all_orders': 
                        const totalOrders = AllOrdersReport.data?.length || 1;
                        const successfulOrders = AllOrdersReport.data?.filter(o => o.status_display?.includes('Delivered') || o.payment_status?.includes('Already Paid')).length || 0;
                        return `${(successfulOrders * 100 / totalOrders).toFixed(1)}%`;
                      case 'daily_cash_flow': 
                        const dailyTotal = DailyCashFlowReport.data?.reduce((sum, row) => sum + row.total_orders, 0) || 1;
                        const dailyDelivered = DailyCashFlowReport.data?.reduce((sum, row) => sum + row.delivered_orders, 0) || 0;
                        return `${(dailyDelivered * 100 / dailyTotal).toFixed(1)}%`;
                      case 'payment_analysis': 
                        const avgSuccessRate = PaymentAnalysisReport.data?.reduce((sum, row) => sum + row.delivery_success_rate, 0) / (PaymentAnalysisReport.data?.length || 1) || 0;
                        return `${avgSuccessRate.toFixed(1)}%`;
                      case 'monthly_summary': 
                        const monthlyAvgRate = MonthlyFinancialSummary.data?.reduce((sum, row) => sum + row.delivery_success_rate, 0) / (MonthlyFinancialSummary.data?.length || 1) || 0;
                        return `${monthlyAvgRate.toFixed(1)}%`;
                      case 'business_metrics': 
                        return `${BusinessMetricsDashboard.data?.[0]?.overall_delivery_rate || 0}%`;
                      default: 
                        return "0%";
                    }
                  })()}}
